+  --neon2: #e879f9;
+  --red: #ef4444;
+  --red-glow: rgba(239,68,68,0.4);
+  --card-bg: #1a1a2e;
+  --card-border: #2a2a4a;
+  --card-back: #16213e;
+  --text: #fafafa;
+  --muted: #555;
+}
+
+body {
+  background: var(--bg);
+  color: var(--text);
+  font-family: 'Inter', sans-serif;
+  min-height: 100vh;
+  overflow-x: hidden;
+  user-select: none;
+  -webkit-user-select: none;
+}
+
+/* CRT scanlines */
+body::after {
+  content: '';
+  position: fixed;
+  inset: 0;
+  background: repeating-linear-gradient(
+    to bottom,
+    transparent 0, transparent 3px,
+    rgba(0,0,0,0.06) 3px, rgba(0,0,0,0.06) 4px
+  );
+  pointer-events: none;
+  z-index: 9999;
+}
+
+/* ── Header ───────────────────────────────────────────── */
+#header {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  padding: 0.75rem 1rem;
+  border-bottom: 1px solid #1a1a1a;
+  position: relative;
+  z-index: 100;
+}
+
+.back-btn {
+  font-family: 'Press Start 2P', monospace;
+  font-size: 0.45rem;
+  color: #444;
+  background: transparent;
+  border: 1px solid #2a2a2a;
+  padding: 0.5rem 0.875rem;
+  cursor: pointer;
+  letter-spacing: 0.05em;
+  transition: color 0.15s, border-color 0.15s;
+  text-decoration: none;
+  display: inline-block;
+}
+.back-btn:hover { color: #fafafa; border-color: #555; }
+
+#title {
+  font-family: 'Press Start 2P', monospace;
+  font-size: clamp(0.5rem, 2vw, 0.75rem);
+  color: var(--neon);
+  text-shadow: 0 0 16px var(--neon-glow);
+  letter-spacing: 0.1em;
+}
+
+#score-display {
+  font-family: 'Press Start 2P', monospace;
+  font-size: 0.45rem;
+  color: #aaa;
+  text-align: right;
+  line-height: 1.8;
+}
+#score-display span { color: var(--neon); }
+
+/* ── Controls bar ─────────────────────────────────────── */
+#controls {
+  display: flex;
+  gap: 0.5rem;
+  align-items: center;
+  justify-content: center;
+  padding: 0.5rem 1rem;
+  flex-wrap: wrap;
+}
+
+.ctrl-btn {
+  font-family: 'Press Start 2P', monospace;
+  font-size: 0.4rem;
+  color: #666;
+  background: transparent;
+  border: 1px solid #2a2a2a;
+  padding: 0.4rem 0.75rem;
+  cursor: pointer;
