+    SFX.deal();
+  } else {
+    pushHistory();
+    const count = Math.min(DRAW_COUNT, state.stock.length);
+    for (let i = 0; i < count; i++) {
+      const c = state.stock.pop();
+      c.faceUp = true;
+      state.waste.push(c);
+    }
+    SFX.draw();
+  }
+  moves++;
+  updateScoreDisplay();
+  render();
