+      const fi = autoMoveToFoundation(c);
+      if (fi !== -1) {
+        state.foundations[fi].push(state.waste.pop());
+        score += 10; moves++;
+        moved = true;
+      }
+    }
+    // Try each tableau column (top card)
+    if (!moved) {
+      for (let col = 0; col < 7; col++) {
+        const pile = state.tableau[col];
+        if (!pile.length) continue;
+        const c = pile[pile.length - 1];
+        const fi = autoMoveToFoundation(c);
+        if (fi !== -1) {
+          state.foundations[fi].push(pile.pop());
+          score += 10; moves++;
+          moved = true;
+          break;
+        }
+      }
+    }
+    if (moved) {
+      SFX.foundation();
+      updateScoreDisplay();
+      render();
+      if (!checkWin()) setTimeout(step, 80);
+    }
+  };
+  step();
+}
