+/* ── Win check ────────────────────────────────────────── */
+function checkWin() {
+  const won = state.foundations.every(f => f.length === 13);
+  if (won) {
+    SFX.win();
+    const bonus = Math.max(0, 10000 - moves * 10);
+    score += bonus;
+    updateScoreDisplay();
+    setTimeout(() => {
+      document.getElementById('win-stats').textContent =
