+
+  // Try waste → foundation
+  if (state.waste.length) {
+    const c = state.waste[state.waste.length - 1];
+    if (autoMoveToFoundation(c) !== -1) {
+      highlightCard(c);
+      hintTimer = setTimeout(clearHighlights, 1500);
+      return;
+    }
+  }
+  // Try waste → tableau
+  if (state.waste.length) {
+    const c = state.waste[state.waste.length - 1];
+    for (let col of state.tableau) {
+      if (canPlaceOnTableau(c, col)) {
+        highlightCard(c);
+        hintTimer = setTimeout(clearHighlights, 1500);
+        return;
+      }
+    }
+  }
+  // Try tableau → foundation
+  for (let col of state.tableau) {
+    if (!col.length) continue;
+    const c = col[col.length - 1];
+    if (autoMoveToFoundation(c) !== -1) {
+      highlightCard(c);
+      hintTimer = setTimeout(clearHighlights, 1500);
+      return;
+    }
+  }
+  // Try tableau → tableau
+  for (let si = 0; si < 7; si++) {
+    const src = state.tableau[si];
+    // find face-up start
+    const startIdx = src.findIndex(c => c.faceUp);
+    if (startIdx === -1) continue;
+    for (let ci = startIdx; ci < src.length; ci++) {
+      const c = src[ci];
+      for (let di = 0; di < 7; di++) {
+        if (di === si) continue;
+        if (canPlaceOnTableau(c, state.tableau[di])) {
