+    el.innerHTML = `<div class="pile-label">WASTE</div>`;
+    return;
+  }
+  // Show top card (or top 3 fanned if draw-3)
+  const top = state.waste.length - 1;
+  if (DRAW_COUNT === 1 || state.waste.length === 1) {
+    el.innerHTML = cardHTML(state.waste[top]);
+    el.querySelector('.card').style.position = 'absolute';
+    el.querySelector('.card').style.top = '0';
+    el.querySelector('.card').style.left = '0';
+  } else {
+    // Fan last 3
+    const fanCount = Math.min(3, state.waste.length);
