   916→+function renderTableau() {
   917→+  const cw = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--cw'));
   918→+  const cascadeDown = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--cascade'));
   919→+  const cascadeFace = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--cascade-face'));
   920→+
   921→+  for (let col = 0; col < 7; col++) {
