   924→+    if (!pile.length) { el.innerHTML = ''; continue; }
   925→+
   926→+    let html = '';
   927→+    let totalHeight = 0;
   928→+    pile.forEach((card, idx) => {
   929→+      const offset = idx === 0 ? 0 : totalHeight;
   930→+      const step = card.faceUp ? cascadeFace : cascadeDown;
   931→+      html += cardHTML(card, `position:absolute;top:${offset}px;left:0;`);
   932→+      if (idx < pile.length - 1) {
   933→+        totalHeight += (pile[idx + 1].faceUp ? cascadeFace : cascadeDown);
   934→+      }
   935→+    });
   936→+
