   977→+
   978→+function bindCardInteraction(pileEl, srcType, srcIdx) {
   979→+  const cards = pileEl.querySelectorAll('.card');
   980→+  cards.forEach((cardEl, visualIdx) => {
   981→+    // Determine actual card index in pile array
   982→+    const actualIdx = getActualCardIdx(cardEl, srcType, srcIdx);
   983→+    if (actualIdx === -1) return;
   984→+
   985→+    // Only face-up cards (or stock for foundation)
