  1036→+function handleDblClick(srcType, srcIdx, cardIdx) {
  1037→+  ensureAudio();
  1038→+  const card = getCardData(srcType, srcIdx, cardIdx);
  1039→+  if (!card || !card.faceUp) return;
  1040→+
  1041→+  // Only move single top card
  1042→+  const isTop = (() => {
  1043→+    if (srcType === 'waste')      return cardIdx === state.waste.length - 1;
  1044→+    if (srcType === 'foundation') return cardIdx === state.foundations[srcIdx].length - 1;
  1045→+    if (srcType === 'tableau')    return cardIdx === state.tableau[srcIdx].length - 1;
  1046→+    return false;
  1047→+  })();
  1048→+  if (!isTop) return;
