  1053→+/* ── Drag start ───────────────────────────────────────── */
  1054→+function startDrag(clientX, clientY, cardEl, srcType, srcIdx, cardIdx) {
  1055→+  ensureAudio();
  1056→+  const cardData = getCardData(srcType, srcIdx, cardIdx);
  1057→+  if (!cardData || !cardData.faceUp) return;
  1058→+
  1059→+  // Collect cards to drag (for tableau: entire sequence from cardIdx)
  1060→+  let dragCards = [];
  1061→+  if (srcType === 'tableau') {
  1062→+    dragCards = state.tableau[srcIdx].slice(cardIdx);
  1063→+  } else if (srcType === 'waste') {
  1064→+    dragCards = [state.waste[state.waste.length - 1]];
  1065→+    cardIdx = state.waste.length - 1;
  1066→+  } else if (srcType === 'foundation') {
  1067→+    dragCards = [state.foundations[srcIdx][state.foundations[srcIdx].length - 1]];
  1068→+    cardIdx = state.foundations[srcIdx].length - 1;
  1069→+  }
  1070→+
  1071→+  if (!dragCards.length) return;
  1072→+
  1073→+  const rect = cardEl.getBoundingClientRect();
  1074→+
  1075→+  // Create ghost element
  1076→+  const ghost = document.createElement('div');
  1077→+  ghost.style.cssText = `
  1078→+    position:fixed;
  1079→+    top:${rect.top}px;
  1080→+    left:${rect.left}px;
  1081→+    z-index:9000;
  1082→+    pointer-events:none;
  1083→+    width:var(--cw);
