  1085→+
  1086→+  // Stack all drag cards in ghost
  1087→+  const ch = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--ch'));
  1088→+  const cascadeFace = parseInt(getComputedStyle(document.documentElement).getPropertyValue('--cascade-face'));
  1089→+  ghost.style.height = (ch + (dragCards.length - 1) * cascadeFace) + 'px';
  1090→+
  1091→+  dragCards.forEach((c, i) => {
  1092→+    const d = document.createElement('div');
  1093→+    d.innerHTML = cardHTML(c, `position:absolute;top:${i * cascadeFace}px;left:0;`);
  1094→+    const inner = d.firstElementChild;
  1095→+    inner.classList.add('dragging');
  1096→+    ghost.appendChild(inner);
  1097→+  });
  1098→+
  1099→+  document.body.appendChild(ghost);
  1100→+
  1101→+  drag = {
  1102→+    cards: dragCards,
  1103→+    srcType, srcIdx, cardIdx,
  1104→+    ghostEl: ghost,
  1105→+    offsetX: clientX - rect.left,
  1106→+    offsetY: clientY - rect.top,
  1107→+  };
  1108→+
  1109→+  SFX.flip();
  1110→+
  1111→+  // Hide original cards (mark as dragging)
  1112→+  markDragging(srcType, srcIdx, cardIdx, true);
  1113→+  render();
