  1115→+  // Bind move/end
  1116→+  document.addEventListener('mousemove', onDragMove);
  1117→+  document.addEventListener('mouseup',   onDragEnd);
  1118→+  document.addEventListener('touchmove', onTouchMove, { passive: false });
  1119→+  document.addEventListener('touchend',  onTouchEnd);
